import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import s from './Auth.module.css';

export default function Login() {
  const nav = useNavigate();
  const { login } = useAuth();
  const [form, setForm] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const onSubmit = async e => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      await login(form.email, form.password);
      nav('/chat');
    } catch (err) {
      setError(err.response?.data?.detail || 'Email ou mot de passe invalide.');
    } finally { setLoading(false); }
  };

  return (
    <div className={s.page}>
      <div className={s.bg1} /><div className={s.bg2} />
      <button onClick={() => nav('/')} className={s.back}>← Retour</button>
      <div className={s.card}>
        <div className={s.cardLogo}><img src="/logo.png" alt="Logo" style={{ width: 40 }} /></div>
        <h1 className={s.title}>Bon retour !</h1>
        <p className={s.sub}>Connectez-vous pour continuer</p>
        {error && <div className={s.err}>{error}</div>}
        <form onSubmit={onSubmit} className={s.form}>
          <div className={s.field}>
            <label className={s.label}>Email</label>
            <input className={s.input} type="email" value={form.email} onChange={e => setForm({...form, email: e.target.value})} required />
          </div>
          <div className={s.field}>
            <label className={s.label}>Mot de passe</label>
            <input className={s.input} type="password" value={form.password} onChange={e => setForm({...form, password: e.target.value})} required />
          </div>
          <button className={s.submit} disabled={loading}>{loading ? 'Connexion...' : 'Se connecter →'}</button>
        </form>
        <p className={s.switch}>Pas encore de compte ? <Link to="/register" className={s.link}>Créer un compte</Link></p>
      </div>
    </div>
  );
}
